// Merge main + overdue voucherlists, deduplicate, prepare detail URLs
const mainData = $('Fetch Voucherlist Main').first().json;
const overdueData = $('Fetch Voucherlist Overdue').first().json;

const mainContent = mainData.content || [];
const overdueContent = overdueData.content || [];

// Deduplicate: overdue overrides main
const map = new Map();
for (const v of mainContent) map.set(v.id, v);
for (const v of overdueContent) map.set(v.id, { ...v, voucherStatus: 'overdue' });

const merged = Array.from(map.values());

if (merged.length === 0) {
  return { json: { _empty: true, count: 0 } };
}

// Each item gets a detail_url for the next HTTP Request node
return merged.map(v => ({
  json: {
    voucher_id: v.id,
    voucher_type: v.voucherType,
    voucher_status: v.voucherStatus,
    voucher_number: v.voucherNumber,
    voucher_date: v.voucherDate,
    due_date: v.dueDate || null,
    contact_id: v.contactId || null,
    contact_name: v.contactName || null,
    total_amount: v.totalAmount || 0,
    open_amount: v.openAmount || 0,
    currency: v.currency || 'EUR',
    updated_date: v.updatedDate,
    detail_url: v.voucherType === 'creditnote'
      ? `https://api.lexware.io/v1/credit-notes/${v.id}`
      : `https://api.lexware.io/v1/invoices/${v.id}`
  }
}));

// Map Lexware detail to BG sales_invoices schema
const detail = $json;
const voucher = $('Merge & Prepare Items').item.json;

// Type mapping
const typeMap = { 'invoice': 'SCHLUSS', 'creditnote': 'GUTSCHRIFT', 'downpaymentinvoice': 'ABSCHLAG' };
const statusMap = { 'draft': 'DRAFT', 'open': 'SENT', 'paid': 'PAID', 'paidoff': 'PAIDOFF', 'voided': 'VOIDED', 'overdue': 'OVERDUE', 'accepted': 'SENT', 'rejected': 'REJECTED' };

const totalPrice = detail.totalPrice || {};
const address = detail.address || {};
const addressStr = [address.street, `${address.zip || ''} ${address.city || ''}`].filter(Boolean).join(', ').trim();
const extractDate = (d) => d ? d.substring(0, 10) : null;

return {
  json: {
    voucher_id: voucher.voucher_id,
    voucher_number: detail.voucherNumber || voucher.voucher_number,
    invoice_type: typeMap[voucher.voucher_type] || 'SCHLUSS',
    status: statusMap[voucher.voucher_status] || 'SENT',
    invoice_date: extractDate(detail.voucherDate || voucher.voucher_date),
    due_date: extractDate(detail.dueDate || voucher.due_date),
    total_net: totalPrice.totalNetAmount || 0,
    vat_amount: totalPrice.totalTaxAmount || 0,
    total_gross: totalPrice.totalGrossAmount || voucher.total_amount || 0,
    vat_rate: 19,
    currency: totalPrice.currency || voucher.currency || 'EUR',
    customer_name: (address.name || voucher.contact_name || '').replace(/'/g, "''"),
    customer_address: addressStr.replace(/'/g, "''"),
    lexware_contact_id: address.contactId || voucher.contact_id || null,
    raw_data: JSON.stringify(detail).replace(/'/g, "''")
  }
};

// Detail fetch error — log and skip this item
const voucher = $('Merge & Prepare Items').item.json;
return { json: { voucher_id: voucher.voucher_id, error: true } };

